import React from 'react';
import { borders } from './borders';
import { shadows } from './shadows';

type PortraitStyle = 'circular' | 'rounded' | 'framed' | 'editorial' | 'vip';

interface PortraitProps {
  src?: string;
  fallback?: React.ReactNode;
  styleVariant?: PortraitStyle;
  className?: string;
}

export const Portrait = ({ src, fallback, styleVariant = 'rounded', className = '' }: PortraitProps) => {
  const getStyleClasses = () => {
    switch (styleVariant) {
      case 'circular':
        return `${borders.radius.full} ${shadows.medium}`;
      case 'framed':
        return `${borders.radius.sm} ${borders.width.thick} border-white ${shadows.heavy}`;
      case 'editorial':
        return `${borders.radius.none} ${shadows.soft}`;
      case 'vip':
        return `${borders.radius.lg} ${borders.width.medium} border-amber-400 ${shadows.glow}`;
      case 'rounded':
      default:
        return `${borders.radius.md} ${borders.width.medium} border-white ${shadows.medium}`;
    }
  };

  return (
    <div className={`relative overflow-hidden bg-white flex items-center justify-center ${getStyleClasses()} ${className}`}>
      {src ? (
        <img
          src={src}
          crossOrigin="anonymous"
          alt="Portrait"
          className="w-full h-full object-cover object-top"
        />
      ) : (
        fallback || (
          <div className="w-full h-full flex items-center justify-center bg-gray-50 text-gray-300">
            <span className="material-symbols-outlined font-light" style={{ fontSize: '40%' }}>person</span>
          </div>
        )
      )}
      <div className="absolute inset-0 ring-1 ring-inset ring-black/10 rounded-[inherit] pointer-events-none" />
    </div>
  );
};
