import { TemplateProps } from '../../types'
import { CandidatePortrait } from '../shared/CandidatePortrait'

export const GeometricTemplate = ({ data }: TemplateProps) => {
  const { supporterName, supporterPhoto, customMessage, colorTheme, aspectRatio } = data
  const isLandscape = ['landscape', 'square', 'print'].includes(aspectRatio)

  // Bauhaus inspired, high contrast primary colors
  const themeColors = {
    green: { bg: '#ffffff', accent1: '#10b981', accent2: '#047857', dark: '#022c22' },
    red: { bg: '#ffffff', accent1: '#ef4444', accent2: '#b91c1c', dark: '#450a0a' },
    blue: { bg: '#ffffff', accent1: '#3b82f6', accent2: '#1d4ed8', dark: '#1e3a8a' },
    gold: { bg: '#ffffff', accent1: '#f59e0b', accent2: '#b45309', dark: '#451a03' },
  }[colorTheme] || { bg: '#ffffff', accent1: '#10b981', accent2: '#047857', dark: '#022c22' }

  return (
    <div className="w-full h-full font-sans overflow-hidden relative select-none" style={{ backgroundColor: themeColors.bg, containerType: 'inline-size' }}>
      
      {/* ── BAUHAUS GEOMETRIC BACKGROUND ── */}
      <div className="absolute inset-0 z-0">
         {/* Huge circle */}
         <div className="absolute -top-[20%] -right-[10%] w-[70%] aspect-square rounded-full mix-blend-multiply opacity-20" style={{ backgroundColor: themeColors.accent1 }} />
         {/* Sharp triangle */}
         <div className="absolute -bottom-[10%] -left-[10%] w-[80%] h-[80%] opacity-10" style={{ backgroundColor: themeColors.accent2, clipPath: 'polygon(0 100%, 100% 100%, 0 0)' }} />
         {/* Structural grid lines */}
         <div className="absolute inset-0 opacity-[0.05] bg-[linear-gradient(rgba(0,0,0,1)_2px,transparent_2px),linear-gradient(90deg,rgba(0,0,0,1)_2px,transparent_2px)] bg-[size:100px_100px]" />
      </div>

      <div className={`relative z-10 w-full h-full flex ${isLandscape ? 'flex-row' : 'flex-col'} p-6 sm:p-8 min-h-0`}>
        
        {/* ================= PHOTOS SECTION ================= */}
        <div className={`flex ${isLandscape ? 'w-1/2 h-full flex-col justify-center' : 'h-[55%] w-full flex-row items-end justify-center'} gap-4 sm:gap-6 relative z-20 min-h-0 shrink-0`}>
          
          {/* Supporter Photo in a strict geometric shape */}
          <div className={`relative ${isLandscape ? 'w-[80%] aspect-square shadow-[10px_10px_0px_rgba(0,0,0,1)] sm:shadow-[15px_15px_0px_rgba(0,0,0,1)]' : 'w-[45%] aspect-square shadow-[6px_6px_0px_rgba(0,0,0,1)] sm:shadow-[10px_10px_0px_rgba(0,0,0,1)]'} bg-white border-2 sm:border-4 border-black overflow-hidden z-20 shrink-0`}>
             {supporterPhoto ? (
               <img src={supporterPhoto} crossOrigin="anonymous" className="w-full h-full object-cover" />
             ) : (
               <div className="w-full h-full flex items-center justify-center bg-slate-100 text-slate-400">
                 <span className="material-symbols-outlined text-[5.56cqw] sm:text-[7.41cqw]">person</span>
               </div>
             )}
             <div className="absolute bottom-0 left-0 bg-black text-white font-black px-2 py-1 text-[0.74cqw] sm:text-[0.93cqw] uppercase tracking-widest">
                Supporter
             </div>
          </div>

          {/* Candidate Photo overlapping */}
          <div className={`relative ${isLandscape ? 'w-[50%] aspect-square absolute bottom-4 sm:bottom-10 -right-2 sm:-right-4 shadow-[10px_10px_0px_rgba(0,0,0,1)] sm:shadow-[15px_15px_0px_rgba(0,0,0,1)]' : 'w-[45%] aspect-square shadow-[6px_6px_0px_rgba(0,0,0,1)] sm:shadow-[10px_10px_0px_rgba(0,0,0,1)] -ml-6 sm:-ml-10 z-10 mb-2 sm:mb-4'} bg-white border-2 sm:border-4 border-black rounded-full overflow-hidden shrink-0`}>
             <CandidatePortrait className="w-full h-full object-cover" />
             <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-full border-[4px] sm:border-[8px] rounded-full pointer-events-none" style={{ borderColor: themeColors.accent1, mixBlendMode: 'multiply' }} />
          </div>

        </div>

        {/* ================= TEXT SECTION ================= */}
        <div className={`flex flex-col ${isLandscape ? 'w-1/2 h-full pl-6 sm:pl-12 justify-center' : 'h-[45%] w-full pt-4 sm:pt-8 justify-center'} relative z-20 min-h-0`}>
          
          {/* Aesthetic block */}
          <div className="w-12 sm:w-16 h-3 sm:h-4 mb-3 sm:mb-6 shrink-0" style={{ backgroundColor: themeColors.accent1 }} />

          <h2 className="font-black uppercase leading-[0.9] tracking-tighter text-black mb-2 sm:mb-4 break-words" style={{ fontSize: '8cqw' }}>
            {supporterName || 'YOUR NAME'}
          </h2>
          
          <div className="bg-black text-white p-2 sm:p-4 inline-block self-start mb-3 sm:mb-6 border-l-[4px] sm:border-l-[8px] shadow-[4px_4px_0px_rgba(0,0,0,0.2)] sm:shadow-[8px_8px_0px_rgba(0,0,0,0.2)] shrink-0" style={{ borderColor: themeColors.accent1 }}>
            <h3 className="font-bold uppercase tracking-widest" style={{ fontSize: '2.51cqw' }}>
              ENDORSES HON. HASSAN
            </h3>
          </div>

          <p className="font-black italic uppercase tracking-wide leading-tight max-w-md break-words shrink-0" style={{ color: themeColors.accent2, fontSize: '1.53cqw' }}>
            "{customMessage || 'BUILDING THE FUTURE'}"
          </p>

          <div className="mt-auto flex items-center justify-between border-t-2 sm:border-t-4 border-black pt-2 sm:pt-4 shrink-0">
             <div className="flex gap-1.5 sm:gap-2">
               <div className="w-3 h-3 sm:w-4 sm:h-4 bg-black rounded-full" />
               <div className="w-3 h-3 sm:w-4 sm:h-4 bg-black" />
               <div className="w-3 h-3 sm:w-4 sm:h-4 bg-black" style={{ clipPath: 'polygon(50% 0%, 0% 100%, 100% 100%)' }} />
             </div>
             <p className="font-black uppercase tracking-[0.3em] text-black" style={{ fontSize: '2cqw' }}>2027 CAMPAIGN</p>
          </div>
        </div>

      </div>

      {/* Frame border */}
      <div className="absolute inset-0 border-[16px] border-black pointer-events-none z-50" />
    </div>
  )
}
