import React from 'react';
import { typography } from './typography';
import { spacing } from './spacing';
import { colors } from './colors';

interface BadgeProps {
  text: string;
  variant?: 'primary' | 'secondary' | 'outline' | 'vip';
  className?: string;
}

export const Badge = ({ text, variant = 'primary', className = '' }: BadgeProps) => {
  const getVariantStyles = () => {
    switch (variant) {
      case 'secondary':
        return 'bg-black/10 text-black/80';
      case 'outline':
        return 'border-[0.2cqw] border-current text-current bg-transparent';
      case 'vip':
        return 'bg-gradient-to-r from-amber-400 to-amber-600 text-white shadow-[0_4px_12px_rgba(251,191,36,0.3)]';
      case 'primary':
      default:
        return 'bg-[#15803D] text-white shadow-sm';
    }
  };

  return (
    <span 
      className={`inline-flex items-center justify-center px-[2cqw] py-[0.8cqw] rounded-full ${typography.roles.label} ${getVariantStyles()} ${className}`}
      style={{ fontSize: typography.sizes.caption }}
    >
      {text}
    </span>
  );
};
